it("should return premium 5 for a quote with an empty item list (processing fee only)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [{ op: "quote", items: [] }],
  };

  expect(processScenario(scenario)).toEqual({ results: [{ premium: 5 }] });
});

